const raw = $json.body ?? $json;
let body = raw;
if (typeof raw === 'string') {
  try { body = JSON.parse(raw); } catch (_) {}
}

const action = body.action || 'criar_cobranca';
const apiKey = this.getEnv('ASAAS_API_KEY');
const headers = { 'access_token': apiKey, 'Content-Type': 'application/json' };
const base = this.getEnv('ASAAS_BASE_URL') || 'https://api.asaas.com/v3';

async function req(method, url, body) {
  const opts = { method, url, headers, json: true };
  if (body) opts.body = body;
  return await this.helpers.httpRequest(opts);
}

function addDaysISO(days) {
  const d = new Date();
  d.setDate(d.getDate() + days);
  return d.toISOString().slice(0, 10);
}

function errInfo(err) {
  return {
    status: err?.statusCode || err?.response?.status || err?.response?.statusCode || err?.cause?.status,
    message: err?.message || String(err),
    data: err?.response?.data
  };
}

if (action === 'cancelar_por_usuario') {
  if (!body.userId) return [{ json: { success: false, error: 'userId ausente' } }];

  let payments = [];
  const listByRef = await req('GET', base + '/payments?externalReference=' + body.userId + '&limit=100');
  payments = listByRef.data || [];

  if (!payments.length) {
    const customers = await req('GET', base + '/customers?externalReference=' + body.userId);
    const customerId = customers?.data?.[0]?.id;
    if (customerId) {
      const listByCustomer = await req('GET', base + '/payments?customer=' + customerId + '&limit=100');
      payments = listByCustomer.data || [];
    }
  }

  const pending = payments.filter(p => ['PENDING','OVERDUE'].includes(p.status));
  let cancelled = 0;
  const failed = [];

  for (const p of pending) {
    try {
      await req('POST', base + '/payments/' + p.id + '/cancel');
      cancelled++;
      continue;
    } catch (err) {
      // Tenta DELETE como fallback
      try {
        await req('DELETE', base + '/payments/' + p.id);
        cancelled++;
        continue;
      } catch (err2) {
        failed.push({ id: p.id, cancel: errInfo(err), del: errInfo(err2) });
      }
    }
  }

  return [{ json: { success: true, cancelled, totalFound: payments.length, failed } }];
}

if (action === 'criar_cobranca') {
  if (!body.userId) return [{ json: { success: false, error: 'userId ausente' } }];

  const instanceCount = Number(body.instanceCount || body.instances || 0);
  const price = Number(body.pricePerInstance || 99);
  const amount = Number(body.amount || 0) || (instanceCount * price);
  if (!amount || amount <= 0) {
    return [{ json: { success: false, error: 'Valor invalido para cobranca' } }];
  }

  const dueDate = body.dueDate || addDaysISO(5);
  const description = body.description || 'Disparo PRO - ' + (instanceCount || 1) + ' instancia(s) x R$ ' + price;

  const searchRes = await req('GET', base + '/customers?externalReference=' + body.userId);
  let customerId;

  if (searchRes.totalCount > 0) {
    customerId = searchRes.data[0].id;
    const upd = { name: body.userName, mobilePhone: body.userPhone };
    if (body.userCpf) upd.cpfCnpj = body.userCpf;
    try { await req('PUT', base + '/customers/' + customerId, upd); } catch (_) {}
  } else {
    const newCustomer = await req('POST', base + '/customers', {
      name: body.userName,
      mobilePhone: body.userPhone,
      cpfCnpj: body.userCpf,
      externalReference: body.userId,
      notificationDisabled: false
    });
    if (!newCustomer.id) {
      return [{ json: { success: false, error: 'Falha ao criar cliente: ' + JSON.stringify(newCustomer) } }];
    }
    customerId = newCustomer.id;
  }

  const payment = await req('POST', base + '/payments', {
    customer: customerId,
    billingType: 'UNDEFINED',
    value: amount,
    dueDate,
    description,
    externalReference: body.userId
  });

  if (!payment.id) {
    const errMsg = payment.errors?.[0]?.description || payment.description || JSON.stringify(payment);
    return [{ json: { success: false, error: errMsg } }];
  }

  let extRef = body.userId;
  try {
    const paymentDetails = await req('GET', base + '/payments/' + payment.id);
    if (paymentDetails?.externalReference) extRef = paymentDetails.externalReference;
  } catch (_) {}

  return [{ json: {
    success: true,
    paymentId: payment.id,
    customerId: payment.customer,
    status: payment.status,
    invoiceUrl: payment.invoiceUrl || null,
    bankSlipUrl: payment.bankSlipUrl || null,
    dueDate: payment.dueDate,
    value: payment.value,
    externalReference: extRef,
    sentExternalReference: body.userId
  } }];
}

return [{ json: { success: false, error: 'acao invalida: ' + action } }];
